import { Request, Response, NextFunction } from 'express';
import { AuthService } from './auth.service';
import { RegisterDto, LoginDto } from './auth.dto';
import { validateAuthRegister, validateAuthLogin } from './auth.validator';
import { AppError } from '../../types/app-error';

export class AuthController {
  private authService: AuthService;

  constructor() {
    this.authService = new AuthService();
  }

  public async register(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const registerData = validateAuthRegister(req.body);
      const result = await this.authService.register(registerData);
      res.status(201).json({ success: true, data: result, meta: { timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      next(new AppError('AUTH_REGISTER_FAILED', 'Failed to register user', 400, error));
    }
  }

  public async login(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const loginData = validateAuthLogin(req.body);
      const token = await this.authService.login(loginData);
      res.status(200).json({ success: true, data: { token }, meta: { timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      next(new AppError('AUTH_LOGIN_FAILED', 'Failed to login user', 401, error));
    }
  }
}

import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { UserRepository } from '../user/user.repository';
import { RegisterDto, LoginDto } from './auth.dto';
import { AppError } from '../../types/app-error';
import { config } from '../../config/env';

export class AuthService {
  private userRepository: UserRepository;

  constructor() {
    this.userRepository = new UserRepository();
  }

  public async register(data: RegisterDto): Promise<void> {
    const { username, password, email } = data;
    const hashedPassword = await bcrypt.hash(password, 10);
    await this.userRepository.createUser({ username, email, passwordHash: hashedPassword });
  }

  public async login(data: LoginDto): Promise<string> {
    const { username, password } = data;
    const user = await this.userRepository.findUserByUsername(username);

    if (!user) {
      throw new AppError('USER_NOT_FOUND', 'User not found', 404);
    }

    const isPasswordValid = await bcrypt.compare(password, user.passwordHash);

    if (!isPasswordValid) {
      throw new AppError('INVALID_PASSWORD', 'Invalid password', 401);
    }

    const token = jwt.sign({ userId: user.id }, config.JWT_SECRET, { expiresIn: '1h' });
    return token;
  }
}

export interface RegisterDto {
  username: string;
  password: string;
  email: string;
}

export interface LoginDto {
  username: string;
  password: string;
}

import { z } from 'zod';

const registerSchema = z.object({
  username: z.string().min(3).max(30),
  password: z.string().min(6),
  email: z.string().email()
});

const loginSchema = z.object({
  username: z.string().min(3).max(30),
  password: z.string().min(6)
});

export const validateAuthRegister = (data: unknown) => registerSchema.parse(data);
export const validateAuthLogin = (data: unknown) => loginSchema.parse(data);

import { Schema, model, Document } from 'mongoose';

interface User extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const userSchema = new Schema<User>({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now }
});

export const UserModel = model<User>('User', userSchema);

import { UserModel } from './user.model';
import { RegisterDto } from '../auth/auth.dto';

export class UserRepository {
  public async createUser(data: RegisterDto & { passwordHash: string }): Promise<void> {
    const user = new UserModel(data);
    await user.save();
  }

  public async findUserByUsername(username: string) {
    return UserModel.findOne({ username });
  }
}
